local LMatchThreeGameBaseCtrl = LXImport(".LMatchThreeGameBaseCtrl")

---@class LMatchThreeGamePosCtrl:LMatchThreeGameBaseCtrl
local LMatchThreeGamePosCtrl = LxClass("LMatchThreeGamePosCtrl", LMatchThreeGameBaseCtrl)
-----------------------------------------------------------------

local Vector3 = Vector3
local math = math

-----------------------------------------------------------------
function LMatchThreeGamePosCtrl:LMatchThreeGamePosCtrl()
    -- 行数
    self._row = 8
    -- 列数
    self._col = 6
    -- 总数
    self._total = self._row * self._col

    -- 行的间隔
    self._rowSpace = 0
    -- 列的间隔
    self._colSpace = 0
    -- 节点大小
    self._nodeW = 0.7
    self._nodeH = 0.65

    -- 生产时，与一行的距离差值
    self._firstOffY = self._nodeH - 0.1

    -- 节点半径开方，取宽高最大值
    self._nodeR2 = (self._nodeW * 0.5 * 100) ^ 2

    -- 数据列表(全部)
    self._dataMap = {}

    -- 相机
    self._camera = gLGameScene:GetCurrentSceneCamera()
end

-- 销毁
function LMatchThreeGamePosCtrl:OnDestroy()

end

-- 获取行数
function LMatchThreeGamePosCtrl:GetRow()
    return self._row
end

-- 获取列数
function LMatchThreeGamePosCtrl:GetCol()
    return self._col
end

-- 获取总数
function LMatchThreeGamePosCtrl:GetTotal()
    return self._total
end

-- 初始化
function LMatchThreeGamePosCtrl:Init()
    self._dataMap = {}
    self._canUseMap = {}
    local nodeRoot = self:GetNodeParent()

    local firstPos = nodeRoot.position
    local firstX = firstPos.x
    local firstY = firstPos.y
    local nodeW = self._nodeW
    local nodeH = self._nodeH

    local ref = gModelMatchThreeGame:GetRef()
    local emptysMap = ModelMatchThreeGame:ListToMap(ref.emptys)

    local index = 0
    for y = 1, self._row do
        for x = 1, self._col do
            local pos = Vector3(0, 0, 0)
            pos.x = firstX + (x - 1) * nodeW + (x - 1) * self._colSpace
            pos.y = firstY - ((y - 1) * nodeH + (y - 1) * self._rowSpace)
            local screenPos = 0--self._camera:WorldToScreenPoint(pos)
            index = index + 1
            local data = { pos = pos, screenPos = screenPos }


            if not emptysMap[index] then
                self._dataMap[index] = data
            end
        end
    end

    for index = 1, self._col do
        local data = self._dataMap[index]
        if data then
            local pos = Vector3(data.pos.x, data.pos.y + self._firstOffY, 0)
            local screenPos = 0--self._camera:WorldToScreenPoint(pos)
            self._dataMap[-index] = { pos = pos, screenPos = screenPos }
        end
    end
end

-- 初始化节点的屏幕位置
function LMatchThreeGamePosCtrl:InitNodeScreenPos()
    local camera = self._camera
    for _, data in pairs(self._dataMap) do
        local screenPos = camera:WorldToScreenPoint(data.pos)
        data.screenPos = screenPos
    end
end


-- 获取节点的父节点
function LMatchThreeGamePosCtrl:GetNodeParent()
    if not self._nodeParent then
        local root = self:GetMap():GetMapTrans()
        self._nodeParent = CS.FindTrans(root, "LayerRoot/LayerNode")
    end
    return self._nodeParent
end

-- 获取节点的位置
function LMatchThreeGamePosCtrl:GetData(index)
    return self._dataMap[index]
end

-- 获取节点的世界坐标
function LMatchThreeGamePosCtrl:GetPosByIndex(index)
    return self._dataMap[index].pos
end

-- 获所有可使用的坐标
function LMatchThreeGamePosCtrl:GetAllCanUseData()
    return self._dataMap
end

-- ture:表示index有效
function LMatchThreeGamePosCtrl:IsValid(index)
    if index < 1 or index > self._total then
        return false
    end

    return self._dataMap[index] and true or false
end

-- 获取当前坐标对应的坐标索引，nil表示没有
function LMatchThreeGamePosCtrl:GetIndexByPos(screenPos)
    for index in pairs(self._dataMap) do
        if self:IsInRange(index, screenPos) then
            return index
        end
    end
    return nil
end

-- 判断屏幕坐标是否在范围内 (粗略判断即可)
function LMatchThreeGamePosCtrl:IsInRange(index, posB)
    local data = self:GetData(index)
    local posA = data.screenPos
    local dis = (posA.x - posB.x) * (posA.x - posB.x) + (posA.y - posB.y) * (posA.y - posB.y)
    return self._nodeR2 >= dis
end

-- 获取周围的坐标索引, 如：5的周围坐标为：
--[[
    1 2 3
    4 — 6
    7 8 9
]]
function LMatchThreeGamePosCtrl:GetAroundIndex(index)
    local around = {}
    local min    = 1
    local max    = self._col * self._row
    local row    = self:GetRowIndex(index)
    local list   = {
        {
            index - self._col - 1,
            index - self._col,
            index - self._col + 1,
        },
        {
            index - 1,
            index + 1,
        },
        {
            index + self._col - 1,
            index + self._col,
            index + self._col + 1
        }
    }
    local rowOff = -1
    for i, tab in ipairs(list) do
        for _, v in ipairs(tab) do
            if v >= min and v <= max then
                local curRow = math.ceil(v / self._col)
                if curRow == row + rowOff then
                    table.insert(around, v)
                end
            end
        end
        rowOff = rowOff + 1
    end
    return around
end

-- 获取当前index对应的行索引
function LMatchThreeGamePosCtrl:GetRowIndex(index)
    local row = math.ceil(index / self._col)
    return row
end

-- 获取当前index对应的列索引
function LMatchThreeGamePosCtrl:GetColIndex(index)
    local row = self:GetRowIndex(index)
    local col = index - (row - 1) * self._col
    return col
end

-- 获取当前行的所有坐标索引列表
function LMatchThreeGamePosCtrl:GetRowIndexList(rowIndex)
    if rowIndex < 1 or rowIndex > self._row then
        return {}
    end

    self._rowIndexListMap = self._rowIndexListMap or {}

    if not self._rowIndexListMap[rowIndex] then
        local list = {}
        for x = 1, self._col do
            local index = (rowIndex - 1) * self._col + x
            table.insert(list, index)
        end
        self._rowIndexListMap[rowIndex] = list
    end
    return self._rowIndexListMap[rowIndex]
end

-- 获取当前列的所有坐标索引列表
function LMatchThreeGamePosCtrl:GetColIndexList(colIndex)
    if colIndex < 1 or colIndex > self._col then
        return {}
    end

    self._colIndexListMap = self._colIndexListMap or {}

    if not self._colIndexListMap[colIndex] then
        local list = {}
        for y = 1, self._row do
            local index = (y - 1) * self._col + colIndex
            table.insert(list, index)
        end
        self._colIndexListMap[colIndex] = list
    end
    return self._colIndexListMap[colIndex]
end

-- 准备生产正常对象，需要遍历的index列表, (从左下向上，再从左到右)
function LMatchThreeGamePosCtrl:GetReadyCreateObjIndexList()
    if not self._readyCreateObjIndexList then
        local list = {}
        for x = 1, self._col do
            for y = self._row, 1, -1 do
                local index = (y - 1) * self._col + x
                if self:GetData(index) then
                    table.insert(list, index)
                end
            end
            if #list > 0 then
                table.insert(self._readyCreateObjIndexList, { col = x, indexList = list })
            end
        end
    end
    return self._readyCreateObjIndexList
end

-- 获取反向index列表(即从大到小)
function LMatchThreeGamePosCtrl:GetReverseIndexList()
    if not self._reverseIndexList then
        local list = {}
        for index in pairs(self._dataMap) do
            if index > 0 then
                table.insert(list, index)
            end
        end
        table.sort(list, function(a, b) return a > b end)
        self._reverseIndexList = list
    end
    return self._reverseIndexList
end

return LMatchThreeGamePosCtrl
